export const normaliseSubjectName = (subject) => subject.trim().toLowerCase().replace(/\s+/g, " ");
export const subjectMetaFor = (subject) => vceSubjectCatalogue.find((item) => normaliseSubjectName(item.name) === normaliseSubjectName(subject)) ?? null;
export const isLanguageSubject = (subject) => subjectMetaFor(subject)?.category === "Languages";
